import{_ as n,C as i,o as e,c as d,a2 as r,b as s,w as a,a as l,E as g,a3 as h}from"./chunks/framework.c3r8iWL8.js";const v=JSON.parse('{"title":"Guide: Observability & Monitoring as QA","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/observability-monitoring-qa.md","filePath":"guides/observability-monitoring-qa.md","lastUpdated":1782929962000}'),c={name:"guides/observability-monitoring-qa.md"};function p(m,t,b,u,f,A){const o=i("Mermaid");return e(),d("div",null,[t[1]||(t[1]=r('<h1 id="guide-observability-monitoring-as-qa" tabindex="-1">Guide: Observability &amp; Monitoring as QA <a class="header-anchor" href="#guide-observability-monitoring-as-qa" aria-label="Permalink to &quot;Guide: Observability &amp; Monitoring as QA&quot;">​</a></h1><p><strong>Decision:</strong> How production signals act as a <strong>continuous QA layer</strong> and feed planning — distinct from base instrumentation (<a href="./monitoring-tracing-logging.html">monitoring-tracing-logging.md</a>) and dashboards (<a href="./dashboards-reporting.html">dashboards-reporting.md</a>).</p><p>Related: <a href="./../operations-observability.html">operations-observability.md</a> · <a href="./../sops/SOP-007-incident-response.html">SOP-007</a> · <a href="./../sops/SOP-008-post-incident.html">SOP-008</a></p><hr><h2 id="monitoring-as-qa-vs-traditional-monitoring" tabindex="-1">Monitoring-as-QA vs traditional monitoring <a class="header-anchor" href="#monitoring-as-qa-vs-traditional-monitoring" aria-label="Permalink to &quot;Monitoring-as-QA vs traditional monitoring&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Traditional ops monitoring</th><th>Monitoring as QA</th></tr></thead><tbody><tr><td>&quot;Is it up?&quot;</td><td>&quot;Did this release change behavior vs contract?&quot;</td></tr><tr><td>Page on threshold</td><td>Page on <strong>novel</strong> failure or SLO burn</td></tr><tr><td>Ops owns alerts</td><td>Ops + dev own <strong>regression artifacts</strong></td></tr><tr><td>Fix and close</td><td>Fix + <strong>test in CI</strong> so it never returns</td></tr></tbody></table><p>CI catches known cases; production catches <strong>unknown unknowns</strong> and <strong>integration drift</strong>.</p><hr><h2 id="qa-oriented-patterns" tabindex="-1">QA-oriented patterns <a class="header-anchor" href="#qa-oriented-patterns" aria-label="Permalink to &quot;QA-oriented patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>What it catches</th><th>Pitfall if misconfigured</th></tr></thead><tbody><tr><td><strong>Synthetic canaries</strong></td><td>User journey breaks</td><td>Shallow scripts miss API logic bugs</td></tr><tr><td><strong>SLO error budgets</strong></td><td>Slow degradation</td><td>Budget too loose → silent rot</td></tr><tr><td><strong>Deploy metric diff</strong></td><td>Release caused regression</td><td>No deploy tags → false negatives</td></tr><tr><td><strong>New error class detection</strong></td><td>Novel exceptions</td><td>Allowlist stale → noise or silence</td></tr><tr><td><strong>Anomaly detection</strong></td><td>Unknown unknowns</td><td>Alert fatigue without tuning</td></tr><tr><td><strong>Contract vs prod trace</strong></td><td>Spec behavior drift</td><td>Not comparing to OpenAPI allowlist</td></tr></tbody></table><hr><h2 id="stack-pointer" tabindex="-1">Stack pointer <a class="header-anchor" href="#stack-pointer" aria-label="Permalink to &quot;Stack pointer&quot;">​</a></h2><p>For metrics/logs/traces/RUM/synthetics tooling choices, see <strong><a href="./monitoring-tracing-logging.html">Monitoring, tracing &amp; logging</a></strong>.</p><p>For alert routing, war rooms, postmortems, see <strong><a href="./incident-management.html">Incident management</a></strong>.</p><p>For SLO dashboards and exec reports, see <strong><a href="./dashboards-reporting.html">Dashboards &amp; reporting</a></strong>.</p><hr><h2 id="feedback-loop-to-development" tabindex="-1">Feedback loop to development <a class="header-anchor" href="#feedback-loop-to-development" aria-label="Permalink to &quot;Feedback loop to development&quot;">​</a></h2>',17)),(e(),s(h,null,{default:a(()=>[g(o,{id:"mermaid-166",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20PROD%5BProduction%20signal%5D%20--%3E%20ALERT%5BAlert%20%2F%20ticket%5D%0A%20%20%20%20ALERT%20--%3E%20TRIAGE%5BHuman%20triage%5D%0A%20%20%20%20TRIAGE%20--%3E%20FIX%5BFix%20PR%5D%0A%20%20%20%20TRIAGE%20--%3E%20TEST%5BRegression%20test%20PR%5D%0A%20%20%20%20TRIAGE%20--%3E%20SPEC%5BSpec%20fix%20if%20behavior%20gap%5D%0A%20%20%20%20TRIAGE%20--%3E%20ADR%5BADR%20if%20architectural%5D%0A%20%20%20%20TEST%20--%3E%20CI%5BCI%20blocks%20recurrence%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=r('<table tabindex="0"><thead><tr><th>Action</th><th>Owner</th><th>Pitfall</th></tr></thead><tbody><tr><td>Regression test from incident</td><td>DEV</td><td>Never filed → repeat incident</td></tr><tr><td>Spec amendment</td><td>PO/ARCH</td><td>Blame user error not spec gap</td></tr><tr><td>ADR update</td><td>ARCH</td><td>Same arch mistake twice</td></tr><tr><td>Alert tuning</td><td>SRE</td><td>Permanent mute hides bugs</td></tr></tbody></table><p><strong>Recommended:</strong> Sev-1/2 requires regression test PR within defined SLA (<a href="./../sops/SOP-008-post-incident.html">SOP-008</a>).</p><hr><h2 id="ai-in-the-qa-loop" tabindex="-1">AI in the QA loop <a class="header-anchor" href="#ai-in-the-qa-loop" aria-label="Permalink to &quot;AI in the QA loop&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Use</th><th>Safe pattern</th><th>Pitfall</th></tr></thead><tbody><tr><td>Log clustering during incident</td><td>Human validates clusters</td><td>Auto-remediate from AI guess</td></tr><tr><td>Draft postmortem</td><td>Human edits all sections</td><td>Publish AI text unreviewed</td></tr><tr><td>Suggest regression test</td><td>Human merges after review</td><td>Test asserts wrong behavior</td></tr><tr><td>Anomaly explanation</td><td>Label as hypothesis</td><td>Treat as root cause</td></tr></tbody></table><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Monitoring separate from QA mindset</strong></td><td>Same bug twice</td><td>Mandatory regression artifact</td></tr><tr><td><strong>Canaries in prod only</strong></td><td>Late detection</td><td>Staging synthetics pre-release</td></tr><tr><td><strong>No trace propagation</strong></td><td>Can&#39;t debug AI microservices</td><td>OpenTelemetry standard</td></tr><tr><td><strong>Metrics without SLOs</strong></td><td>Arbitrary alerts</td><td>SLI/SLO per T1</td></tr><tr><td><strong>Logs without structure</strong></td><td>AI correlation useless</td><td>JSON + trace_id</td></tr><tr><td><strong>Skipping postmortem action items</strong></td><td>Process debt</td><td>Track to completion in ticket</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Staging + prod synthetics on critical paths → deploy metric diff with auto-rollback → new-error-class alerts → post-incident regression mandatory → link incidents to spec/ADR updates when applicable.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./automated-testing-qa.html">Automated testing</a> · <a href="./ci-cd-release.html">CI/CD &amp; release</a> · <a href="./data-governance.html">Data governance</a></li></ul>',14))])}const P=n(c,[["render",p]]);export{v as __pageData,P as default};
